using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWebAsync),
    AIFunctionFactory.Create(notebook.TakeNote),
    AIFunctionFactory.Create(notebook.ReadNotes),
};

// ---------------------------------------------------------------------------
// Agent setup
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI research assistant that searches the web and takes notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    });

// ---------------------------------------------------------------------------
// Run the agent
// ---------------------------------------------------------------------------
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching \"{topic}\" — this may take a moment...");
Console.WriteLine();

var prompt = $"""
    You are a research assistant. Your goal is to research the following topic
    and produce a comprehensive summary.

    Topic: {topic}

    Follow these steps:
    1. Search the web for information about the topic (2-3 searches with
       different queries to get broad coverage).
    2. As you find key facts and insights, use the note-taking tool to save
       them so you don't lose track.
    3. After gathering enough information, read your notes and produce a
       well-structured summary of your findings. Include source references
       where possible.

    Begin researching now.
    """;

var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(prompt, session);

Console.WriteLine("══════════════════════════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("══════════════════════════════════════════════════════════════");
Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();

if (notebook.Notes.Count > 0)
{
    Console.WriteLine("──────────────────────────────────────────────────────────────");
    Console.WriteLine("  RAW NOTES");
    Console.WriteLine("──────────────────────────────────────────────────────────────");
    for (int i = 0; i < notebook.Notes.Count; i++)
    {
        Console.WriteLine($"  [{i + 1}] {notebook.Notes[i]}");
    }
    Console.WriteLine();
}

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

/// <summary>
/// Searches the web for the given query and returns a set of result snippets.
/// </summary>
[Description("Search the web for information. Returns titles, URLs, and snippet text.")]
static async Task<string> SearchWebAsync(
    [Description("The search query string")] string query,
    CancellationToken cancellationToken = default)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

    var encoded = Uri.EscapeDataString(query);
    var url = $"https://html.duckduckgo.com/html/?q={encoded}";

    string html;
    try
    {
        html = await http.GetStringAsync(url, cancellationToken);
    }
    catch (HttpRequestException ex)
    {
        return $"Search failed: {ex.Message}";
    }

    // Parse result blocks from the DuckDuckGo HTML response
    var results = new StringBuilder();
    int count = 0;

    foreach (Match block in Regex.Matches(
        html,
        @"<a[^>]+class=""result__a""[^>]*>(?<title>.*?)</a>.*?" +
        @"<a[^>]+class=""result__url""[^>]*href=""(?<url>[^""]*?)""[^>]*>.*?" +
        @"<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
        RegexOptions.Singleline))
    {
        if (++count > 6)
            break;

        var title = StripHtml(block.Groups["title"].Value);
        var link = WebUtility.UrlDecode(block.Groups["url"].Value).Trim();
        var snippet = StripHtml(block.Groups["snippet"].Value);

        // DuckDuckGo wraps actual URLs in a redirect; extract the real one
        var uddg = Regex.Match(link, @"[?&]uddg=([^&]+)");
        if (uddg.Success)
            link = WebUtility.UrlDecode(uddg.Groups[1].Value);

        results.AppendLine($"[{count}] {title}");
        results.AppendLine($"    URL: {link}");
        results.AppendLine($"    {snippet}");
        results.AppendLine();
    }

    return results.Length > 0
        ? results.ToString()
        : "No results found. Try rephrasing the query.";
}

static string StripHtml(string html) =>
    WebUtility.HtmlDecode(Regex.Replace(html, "<.*?>", string.Empty)).Trim();

// ---------------------------------------------------------------------------
// Notebook — the agent's note-taking tool
// ---------------------------------------------------------------------------

/// <summary>In-memory notebook that the agent uses to organize findings.</summary>
sealed class Notebook
{
    public List<string> Notes { get; } = [];

    [Description("Save a note capturing a key finding or insight for later reference.")]
    public string TakeNote(
        [Description("The content of the note to save")] string content)
    {
        Notes.Add(content);
        return $"Note #{Notes.Count} saved.";
    }

    [Description("Read all previously saved notes.")]
    public string ReadNotes()
    {
        if (Notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < Notes.Count; i++)
            sb.AppendLine($"Note #{i + 1}: {Notes[i]}");

        return sb.ToString();
    }
}

